import { createContext, useContext, useState, useEffect, useCallback } from "react";
import api from "../services/api";

const AuthContext = createContext(null);

// Role → portal route mapping
const ROLE_HOME = {
  Candidate:   "/candidate/dashboard",
  TeamMember:  "/employee/dashboard",
  TeamLeader:  "/employee/dashboard",
  HRManager:   "/hr/dashboard",
  Admin:       "/admin/dashboard",
};

export function AuthProvider({ children }) {
  const [user, setUser]       = useState(null);
  const [loading, setLoading] = useState(true); // true while rehydrating from storage

  // Rehydrate on app load — if tokens exist, restore session silently
  useEffect(() => {
    const stored = localStorage.getItem("user");
    const access = localStorage.getItem("access");
    if (stored && access) {
      setUser(JSON.parse(stored));
    }
    setLoading(false);
  }, []);

  const login = useCallback(async (email, password) => {
    const response = await api.post("/auth/login/", { email, password });
    const { access, refresh, role, full_name, employee_id } = response.data;

    const userData = { email, role, full_name, employee_id };

    localStorage.setItem("access",  access);
    localStorage.setItem("refresh", refresh);
    localStorage.setItem("user",    JSON.stringify(userData));

    setUser(userData);
    return ROLE_HOME[role] ?? "/dashboard";
  }, []);

  const logout = useCallback(async () => {
    try {
      const refresh = localStorage.getItem("refresh");
      if (refresh) await api.post("/auth/logout/", { refresh });
    } catch {
      // Blacklist call failed — clear locally anyway
    } finally {
      localStorage.removeItem("access");
      localStorage.removeItem("refresh");
      localStorage.removeItem("user");
      setUser(null);
    }
  }, []);

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, ROLE_HOME }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used inside AuthProvider");
  return ctx;
}
